text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      "공개 릴리스 목표는 스모크 테스트 통과 시 금요일 15:00 KST로 확정됨.",
      "packageName 불일치가 발생하면 스크립트를 무시하지 않고 먼저 패키지 설정을 점검한 뒤, 계약 자체가 잘못된 경우에만 해당 스크립트를 검토함.",
      "Minjun은 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유하기로 함.",
      "Doyun은 금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성하기로 함.",
      "Hara는 Minjun의 스모크 테스트 결과가 올라온 뒤 생성된 tarball 경로를 확인하기로 함."
    ],
    "non_decisions": {
      "rejected_proposals": [
        "Hara가 제안한 'smoke-theme-pack.mjs에서 packageName mismatch를 무시'하는 안은 회의에서 반려됨."
      ],
      "internal_stretch_goals": [
        "수요일 공개는 내부 stretch goal로만 다뤄졌고, 최종 공개 목표는 아님."
      ],
      "undecided_items": [
        "README install steps 검토의 최종 담당자/확정 기한은 미정.",
        "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부는 미결정."
      ]
    },
    "risks": [
      "생성된 tarball 경로가 잘못되면 릴리스 지연 가능성이 있음.",
      "README 설치 단계가 최신이 아니면 릴리스 노트가 사용자에게 오해를 줄 수 있음."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 stretch goal인 수요일 계획을 반영할지 여부는?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 게시 후 생성 tarball 경로 확인",
      "due": "기한 미정 (Minjun 결과 후)",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "미지정",
      "task": "README install steps 검토 및 최신성 확인",
      "due": "기한 미정(목요일 가능 시)",
      "status": "보류",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 전까지 Minjun의 스모크 재실행 결과가 공유되었는지 확인.",
      "금요일 12:00 KST 전까지 Doyun의 실패 트리아지 노트 작성 상태 확인.",
      "Hara의 tarball 경로 확인 결과로 릴리스 blocking 이슈가 해소되었는지 확인.",
      "README install steps 검토 담당자와 최종 마감일 확정.",
      "최종 릴리스 승인 권한자와 수요일 stretch goal 노출 여부를 결정."
    ],
    "what_not_to_invent": [
      "고객명, 예산, 보안 사고, 운영 장애, 법무 승인, 미확인 오너/데드라인 같은 미언급 사실을 생성하지 않는다.",
      "미팅 기록에 없는 추가 승인 절차, 외부 파트너, 수치, 정책을 가정해 넣지 않는다.",
      "프로젝트 범위 밖의 제약이나 조건을 채워 넣지 않는다."
    ]
  },
  "non_invention_rules": [
    "입력된 공개 안전 fixture의 사실만 사용한다.",
    "고객/예산/보안/장애/법적 승인/오너/기한이 명시되지 않은 항목은 '미정' 또는 '미지정'으로만 표기한다.",
    "확정사항, 반려 제안, 내부 stretch goal, 리스크, 오픈 질문을 섞지 않는다.",
    "최종 릴리스 승인자와 수요일 stretch goal 공개 여부는 질문 상태로 유지한다.",
    "절대적으로 확인되지 않은 내용은 추측 없이 제외한다."
  ]
}
